using Azure.Identity;
using Azure.Security.KeyVault.Secrets;

var credential = new ClientSecretCredential(
    tenantId:     Environment.GetEnvironmentVariable("AZURE_TENANT_ID"),
    clientId:     Environment.GetEnvironmentVariable("AZURE_CLIENT_ID"),
    clientSecret: Environment.GetEnvironmentVariable("AZURE_CLIENT_SECRET")
);

var client = new SecretClient(
    new Uri("https://my-vault.vault.azure.net"),
    credential
);

KeyVaultSecret secret = await client.GetSecretAsync("my-secret");
Console.WriteLine(secret.Value);

import { ClientSecretCredential } from '@azure/identity';
import { SecretClient } from '@azure/keyvault-secrets';

const credential = new ClientSecretCredential(
  process.env.AZURE_TENANT_ID!,
  process.env.AZURE_CLIENT_ID!,
  process.env.AZURE_CLIENT_SECRET!
);

const client = new SecretClient('https://my-vault.vault.azure.net', credential);
const secret = await client.getSecret('my-secret');
console.log(secret.value);

Connect-MgGraph -Scopes 'Application.Read.All'

$cutoff = (Get-Date).AddDays(30)

Get-MgApplication -All | ForEach-Object {
    $app = $_
    $app.PasswordCredentials | Where-Object { $_.EndDateTime -lt $cutoff } | ForEach-Object {
        [PSCustomObject]@{
            AppName     = $app.DisplayName
            AppId       = $app.AppId
            SecretName  = $_.DisplayName
            ExpiresOn   = $_.EndDateTime
            DaysLeft    = ($_.EndDateTime - (Get-Date)).Days
        }
    }
} | Sort-Object DaysLeft | Format-Table -AutoSize

resource "azuread_application" "api" {
  display_name = "my-backend-api"
}

resource "azuread_service_principal" "api" {
  client_id = azuread_application.api.client_id
}

# Secret that auto-rotates every 90 days via Terraform plan
resource "time_rotating" "secret_rotation" {
  rotation_days = 90
}

resource "azuread_application_password" "api" {
  application_id  = azuread_application.api.id
  display_name    = "terraform-managed"
  rotate_when_changed = {
    rotation = time_rotating.secret_rotation.id
  }
  end_date_relative = "2160h"  # 90 days
}

# Store the secret in Key Vault (not in plain Terraform output)
resource "azurerm_key_vault_secret" "api_secret" {
  name         = "api-client-secret"
  value        = azuread_application_password.api.value
  key_vault_id = azurerm_key_vault.main.id
}
